import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 

// BRAND COLORS
const gold = '#D4AF37'; 
const terracotta = '#C04000'; 
const softCream = '#FDF5E6'; 

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);
  const [cart, setCart] = useState([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [showBankDetails, setShowBankDetails] = useState(false);
  const [isClockedIn, setIsClockedIn] = useState(false);

  const whatsappNumber = "2349122731172";
  const bankInfo = { 
    bank: "PREMIUMTRUST BANK", 
    account: "0112326977", 
    name: "OLUKOYA OMOTOYOSI" 
  };

  // 1. HEADER SLIDES DATA
  const slides = [
    { title: "SMALL CHOPS", subtitle: "Lagos' finest selection.", bgImage: "/images/chops_bg.jpg" },
    { title: "THE HAIR EDIT", subtitle: "Luxury units & blends.", bgImage: "/images/wigs_bg.jpg" },
    { title: "OFFICE LUNCH", subtitle: "Premium corporate dining.", bgImage: "/images/lunch_bg.jpg" }
  ];

  // 2. MAIN MENU DATA
  const menuData = {
    CHOPS: [
      { id: 1, name: "The Starter Pack", price: "15,000", desc: "7 Samosas, 7 Springrolls, 15 Puff-puff, 10 Mosa, 4 Grilled Chicken.", img: "/images/starter.jpg" },
      { id: 2, name: "The Signature Platter", price: "25,000", desc: "10 Samosas, 10 Springrolls, 25 Puff-puff, 20 Mosa, 8 Grilled Chicken.", img: "/images/signature.jpg" },
      { id: 3, name: "The Owambe Special", price: "150,000", desc: "Full event catering for 50 people.", img: "/images/owambe.jpg" },
      { id: 4, name: "The Customized Package", price: "200,000", desc: "Bespoke menu for 60 people and above.", img: "/images/custom.jpg", isCustom: true }
    ],
    LUNCH: [
      { day: "Monday", meal: "Smoky Jollof, Grilled Chicken & Salad" },
      { day: "Tuesday", meal: "Creamy Pasta, Sauteed Prawns & Garlic Bread" },
      { day: "Wednesday", meal: "Native Rice, Shredded Beef & Fried Plantain" },
      { day: "Thursday", meal: "Stir-fry Noodles, Teriyaki Wings & Veggies" },
      { day: "Friday", meal: "Chef's Special Surprise (TGIF Menu)" }
    ],
    WIGS: [
      { type: "Human Hair", items: [
          { id: 201, name: "Raw Cambodian", price: "85,000", desc: "14\" Frontal Unit", img: "/images/hair1.jpg" },
          { id: 202, name: "Bone Straight", price: "120,000", desc: "12\" Double Drawn", img: "/images/hair2.jpg" }
      ]},
      { type: "Premium Fibre", items: [
          { id: 203, name: "Sleek Straight", price: "35,000", desc: "Heat Resistant", img: "/images/hair3.jpg" },
          { id: 204, name: "Deep Wave", price: "38,000", desc: "Pre-styled", img: "/images/hair4.jpg" }
      ]},
      { type: "Hair Blend", items: [
          { id: 205, name: "Piano Wavy", price: "25,000", desc: "24\" T-Closure", img: "/images/hair5.jpg" }
      ]}
    ]
  };

  useEffect(() => {
    const timer = setInterval(() => setCurrentSlide((s) => (s + 1) % slides.length), 5000);
    return () => clearInterval(timer);
  }, [slides.length]);

  const addToCart = (item) => setCart([...cart, item]);
  const removeFromCart = (index) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };
  const total = cart.reduce((acc, item) => acc + parseInt(item.price.replace(/,/g, '')), 0);

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* 1. STICKY HEADER */}
      <header style={{ padding: '15px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, backgroundColor: 'rgba(0,0,0,0.9)', zIndex: 1000, borderBottom: '1px solid #222' }}>
        <img src={Logo} alt="Logo" style={{ height: '60px' }} />
        <div style={{ fontSize: '1.5rem', color: softCream }}>
          <span style={{ position: 'relative', cursor: 'pointer' }} onClick={() => setIsCartOpen(true)}>🛒
            <span style={{ position: 'absolute', top: '-8px', right: '-12px', background: terracotta, color: '#fff', borderRadius: '50%', padding: '4px 7px', fontSize: '0.8rem', fontWeight: 'bold' }}>{cart.length}</span>
          </span>
        </div>
      </header>

      {/* 2. DYNAMIC HERO BANNER */}
      <div style={{ width: '100%', height: '240px', position: 'relative', overflow: 'hidden' }}>
        {slides.map((slide, index) => (
          <div key={index} style={{ 
            position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', 
            opacity: index === currentSlide ? 1 : 0, transition: 'opacity 1.2s ease-in-out',
            backgroundImage: `url(${process.env.PUBLIC_URL + slide.bgImage})`, 
            backgroundSize: 'cover', backgroundPosition: 'center',
            display: 'flex', flexDirection: 'column', justifyContent: 'center', padding: '0 30px'
          }}>
            {/* DARK OVERLAY FOR TEXT READABILITY */}
            <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'linear-gradient(to right, rgba(0,0,0,0.85), rgba(0,0,0,0.3))' }}></div>
            <div style={{ position: 'relative', zIndex: 2 }}>
              <h2 style={{ fontSize: '2.4rem', fontWeight: '900', margin: 0, letterSpacing: '1px' }}>{slide.title}</h2>
              <p style={{ fontSize: '1.2rem', color: softCream, marginTop: '8px' }}>{slide.subtitle}</p>
            </div>
          </div>
        ))}
      </div>

      {/* 3. NAVIGATION */}
      <div style={{ display: 'flex', gap: '12px', overflowX: 'auto', padding: '20px 30px', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs'].map((item) => (
          <button key={item} onClick={() => setActiveCategory(item)} style={{ whiteSpace: 'nowrap', padding: '12px 24px', borderRadius: '25px', border: 'none', backgroundColor: activeCategory === item ? terracotta : '#1a1a1a', color: '#fff', fontWeight: '700', fontSize: '1rem' }}>
            {item}
          </button>
        ))}
      </div>

      {/* 4. MAIN CONTENT */}
      <main style={{ paddingBottom: '140px' }}>
        
        {/* SMALL CHOPS SECTION */}
        {activeCategory === 'Small Chops' && menuData.CHOPS.map((item) => (
          <div key={item.id} style={{ display: 'flex', backgroundColor: '#111', borderRadius: '16px', margin: '0 25px 18px', padding: '18px', alignItems: 'center', border: '1px solid #222' }}>
            <div style={{ width: '110px', height: '110px', borderRadius: '12px', overflow: 'hidden', marginRight: '18px', flexShrink: 0 }}>
              <img src={item.img} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
            </div>
            <div style={{ flex: 1 }}>
              <h4 style={{ fontSize: '1.1rem', margin: 0, fontWeight: '700' }}>{item.name}</h4>
              <p style={{ fontSize: '0.9rem', color: '#888', margin: '6px 0' }}>{item.desc}</p>
              <div style={{ fontSize: '1.2rem', color: gold, fontWeight: 'bold' }}>₦{item.price}</div>
            </div>
            
            {/* CORRECTED BOOKING/ADD LOGIC */}
            {item.isCustom ? (
              <button 
                onClick={() => window.open(`https://wa.me/${whatsappNumber}?text=Hello! I'd like to book the ${item.name}.`)} 
                style={{ backgroundColor: gold, padding: '12px 18px', borderRadius: '25px', border: 'none', fontWeight: '900', marginLeft: '10px', cursor: 'pointer', fontSize: '0.8rem' }}>
                BOOK
              </button>
            ) : (
              <button 
                onClick={() => addToCart(item)} 
                style={{ backgroundColor: terracotta, padding: '12px 20px', borderRadius: '25px', border: 'none', color: '#fff', fontWeight: '900', marginLeft: '10px', cursor: 'pointer' }}>
                ADD
              </button>
            )}
          </div>
        ))}

        {/* OFFICE LUNCH SECTION */}
        {activeCategory === 'Office Lunch' && (
          <div style={{ padding: '0 30px' }}>
            <div style={{ backgroundColor: '#0A0A0A', border: `2px solid ${isClockedIn ? '#2ecc71' : terracotta}`, padding: '40px 25px', borderRadius: '16px', textAlign: 'center', marginBottom: '25px' }}>
              <h4 style={{ color: isClockedIn ? '#2ecc71' : gold, fontSize: '1.4rem' }}>{isClockedIn ? "Enjoy Your Meal! ✅" : "Good Morning, Champion. ✨"}</h4>
              <button onClick={() => setIsClockedIn(true)} style={{ backgroundColor: isClockedIn ? '#2ecc71' : terracotta, color: '#fff', border: 'none', padding: '16px 35px', borderRadius: '12px', fontWeight: 'bold', marginTop: '20px' }}>CLOCK IN</button>
            </div>
            {menuData.LUNCH.map((item) => (
              <div key={item.day} style={{ padding: '20px 0', borderBottom: '1px solid #222', display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ color: terracotta, fontWeight: '800' }}>{item.day}</span>
                <span style={{ textAlign: 'right', flex: 1, marginLeft: '20px' }}>{item.meal}</span>
              </div>
            ))}
          </div>
        )}

        {/* WIGS SECTION */}
        {activeCategory === 'Wigs' && menuData.WIGS.map((cat) => (
          <div key={cat.type} style={{ padding: '0 30px', marginBottom: '30px' }}>
            <h3 style={{ fontSize: '0.9rem', color: terracotta, textTransform: 'uppercase', marginBottom: '15px', letterSpacing: '2px' }}>{cat.type}</h3>
            {cat.items.map((item) => (
              <div key={item.id} style={{ display: 'flex', backgroundColor: '#111', borderRadius: '16px', marginBottom: '15px', padding: '18px', alignItems: 'center', border: '1px solid #222' }}>
                <div style={{ width: '100px', height: '100px', borderRadius: '12px', overflow: 'hidden', marginRight: '18px', flexShrink: 0 }}>
                  <img src={item.img} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
                </div>
                <div style={{ flex: 1 }}>
                  <h4 style={{ fontSize: '1.1rem', fontWeight: '700' }}>{item.name}</h4>
                  <p style={{ fontSize: '0.9rem', color: '#888' }}>{item.desc}</p>
                  <div style={{ color: gold, fontWeight: 'bold', fontSize: '1.1rem' }}>₦{item.price}</div>
                </div>
                <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, padding: '12px 20px', borderRadius: '25px', border: 'none', color: '#fff', fontWeight: '900' }}>ADD</button>
              </div>
            ))}
          </div>
        ))}
      </main>

      {/* 5. FLOATING CART SUMMARY */}
      {cart.length > 0 && (
        <div onClick={() => setIsCartOpen(true)} style={{ position: 'fixed', bottom: '25px', left: '50%', transform: 'translateX(-50%)', width: '92%', maxWidth: '500px', backgroundColor: terracotta, padding: '20px', borderRadius: '20px', display: 'flex', justifyContent: 'space-between', zIndex: 1001, boxShadow: '0 10px 30px rgba(0,0,0,0.5)', cursor: 'pointer' }}>
          <span style={{ fontWeight: '900' }}>{cart.length} ITEMS</span>
          <span style={{ fontWeight: '900' }}>VIEW CART ₦{total.toLocaleString()}</span>
        </div>
      )}

      {/* 6. CART MODAL */}
      {isCartOpen && (
        <div style={{ position: 'fixed', bottom: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.96)', zIndex: 2000, display: 'flex', alignItems: 'flex-end' }}>
          <div style={{ width: '100%', backgroundColor: '#111', borderTopLeftRadius: '35px', borderTopRightRadius: '35px', padding: '40px 30px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '25px' }}>
              <h3 style={{ color: gold, margin: 0, fontSize: '1.6rem' }}>{showBankDetails ? "Payment" : "Your Box"}</h3>
              <button onClick={() => {setIsCartOpen(false); setShowBankDetails(false);}} style={{ background: 'none', border: 'none', color: '#fff', fontSize: '2rem' }}>✕</button>
            </div>
            {!showBankDetails ? (
              <>
                <div style={{ maxHeight: '40vh', overflowY: 'auto' }}>
                  {cart.map((item, i) => (
                    <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '15px 0', borderBottom: '1px solid #222' }}>
                      <span>{item.name}</span>
                      <span style={{ color: gold, fontWeight: 'bold' }}>₦{item.price}</span>
                    </div>
                  ))}
                </div>
                <div style={{ marginTop: '30px' }}>
                  <button onClick={() => setShowBankDetails(true)} style={{ width: '100%', padding: '20px', backgroundColor: gold, borderRadius: '15px', border: 'none', fontWeight: '900', marginBottom: '10px', fontSize: '1.1rem' }}>BANK TRANSFER</button>
                  <button onClick={() => window.open(`https://wa.me/${whatsappNumber}?text=Order Summary: ${cart.map(c => c.name).join(', ')}. Total: ₦${total.toLocaleString()}`)} style={{ width: '100%', padding: '20px', backgroundColor: '#25D366', borderRadius: '15px', border: 'none', color: '#fff', fontWeight: '900', fontSize: '1.1rem' }}>WHATSAPP ORDER</button>
                </div>
              </>
            ) : (
              <div style={{ textAlign: 'center' }}>
                <h2 style={{ color: gold, fontSize: '2.2rem' }}>₦{total.toLocaleString()}</h2>
                <div style={{ backgroundColor: '#000', padding: '20px', borderRadius: '15px', textAlign: 'left', border: '1px solid #333' }}>
                  <p><strong>Bank:</strong> {bankInfo.bank}</p>
                  <p><strong>Account:</strong> {bankInfo.account}</p>
                  <p><strong>Name:</strong> {bankInfo.name}</p>
                </div>
                <button onClick={() => setShowBankDetails(false)} style={{ marginTop: '20px', background: 'none', border: 'none', color: '#666', textDecoration: 'underline' }}>Back to cart</button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
